import React, { useState } from 'react';
import DiceRoll from 'react-dice-roll';

function App() {
  const [player, setPlayer] = useState('');
  const [position, setPosition] = useState(0);
  const [turn, setTurn] = useState(1);
  const [rotation, setRotation] = useState(0);

  const [diceRolls, setDiceRolls] = useState([]);

  const handleRollDone = (value) => {
    setDiceRolls((prev) => {
      const newRolls = [...prev, value];
      if (newRolls.length === 2) {
        const total = newRolls[0] + newRolls[1];
        setPosition((pos) => (pos + total) % 20);
        setTurn((t) => t + 1);
        return [];
      }
      return newRolls;
    });
  };

  const rotateBoard = () => {
    setRotation((prev) => (prev + 90) % 360);
  };

  // ------------------------------
  // Card stages & questions
  // ------------------------------
  const [cardStage, setCardStage] = useState('parsha'); // 'parsha', 'har', 'tzaddik'
  const [revealed, setRevealed] = useState(false);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [correctCount, setCorrectCount] = useState(0);

  // Card data & back images
  const cardsData = {
    parsha: {
      title: 'Parsha: Bereshit',
      backImage: 'possible-restyle.png',  // Parsha back card image filename
      questions: [
        { q: 'Who was the first person created?', a: 'Adam' },
        { q: 'What did Hashem create on the first day?', a: 'Light' },
        { q: 'What was the sign of the covenant with Noach?', a: 'Rainbow' },
      ],
    },
    har: {
      title: 'Har HaBayit Bonus',
      backImage: 'har habayit 1a.png',  // Har HaBayit back image
      questions: [
        { q: 'What stood on Har HaBayit in ancient times?', a: 'Beit HaMikdash' },
        { q: 'Who was told to sacrifice his son there?', a: 'Avraham' },
      ],
    },
    tzaddik: {
      title: 'Tzaddik Challenge',
      backImage: 'tzadik card.png',  // Tzaddik back image
      questions: [
        { q: 'What does a tzaddik represent in Jewish thought?', a: 'Righteousness' },
        { q: 'Name one famous tzaddik from Tanach.', a: 'Yosef HaTzaddik' },
      ],
    },
  };

  const currentCard = cardsData[cardStage];
  const currentQ = currentCard.questions[currentQuestionIndex];

  const handleReveal = () => setRevealed(true);

  const handleCorrect = () => {
    setCorrectCount((count) => count + 1);
    handleNext();
  };

  const handleNext = () => {
    setRevealed(false);
    if (currentQuestionIndex + 1 < currentCard.questions.length) {
      setCurrentQuestionIndex((i) => i + 1);
    } else {
      // End of questions for this card stage
      if (cardStage === 'parsha' && correctCount === currentCard.questions.length) {
        setCardStage('har');
        resetQuestions();
      } else if (cardStage === 'har' && correctCount === currentCard.questions.length) {
        setCardStage('tzaddik');
        resetQuestions();
      } else {
        resetAll();
      }
    }
  };

  const resetQuestions = () => {
    setCurrentQuestionIndex(0);
    setCorrectCount(0);
    setRevealed(false);
  };

  const resetAll = () => {
    setCardStage('parsha');
    setCurrentQuestionIndex(0);
    setCorrectCount(0);
    setRevealed(false);
  };

  return (
    <div style={{ padding: 20, fontFamily: 'Arial' }}>
      <h1>Monopoly Torah Game</h1>

      <div
        style={{
          maxWidth: '900px',
          marginBottom: '20px',
          border: '2px solid #000',
          display: 'inline-block',
          transform: `rotate(${rotation}deg)`,
          transition: 'transform 0.5s ease',
        }}
      >
        <img
          src={`${process.env.PUBLIC_URL}/torahpoly_board.png`}
          alt="Monopoly Board"
          style={{ maxWidth: '100%', height: 'auto', display: 'block' }}
        />
      </div>

      <div>
        <button
          onClick={rotateBoard}
          style={{
            padding: '10px 20px',
            fontSize: '16px',
            marginBottom: '20px',
            cursor: 'pointer',
          }}
        >
          Rotate Board
        </button>
      </div>

      <input
        placeholder="Enter your player name"
        value={player}
        onChange={(e) => setPlayer(e.target.value)}
        style={{
          padding: '8px',
          fontSize: '16px',
          width: '100%',
          maxWidth: '300px',
          marginBottom: '10px',
        }}
      />

      <p>Turn: {turn}</p>
      <p>Player: {player || 'No player yet'}</p>
      <p>Position: {position}</p>

      <div style={{ display: 'flex', gap: '20px', marginBottom: '20px' }}>
        <DiceRoll onRollDone={handleRollDone} size={100} />
        <DiceRoll onRollDone={handleRollDone} size={100} />
      </div>

      {/* Card Section */}
      <div
        style={{
          borderTop: '2px solid #000',
          paddingTop: '20px',
          maxWidth: '400px',
          margin: '40px auto 0',
          textAlign: 'center',
          border: '2px solid black',
          padding: '20px',
          borderRadius: '8px',
        }}
      >
        <h2>{currentCard.title}</h2>

        {!revealed ? (
          <>
            {/* Show back side image */}
            <img
              src={`${process.env.PUBLIC_URL}/cards/${currentCard.backImage}`}
              alt={`${currentCard.title} Card Back`}
              style={{ width: '300px', border: '2px solid black', marginBottom: '20px' }}
            />
            <p style={{ fontSize: '18px', fontWeight: 'bold' }}>
              Click to reveal question {currentQuestionIndex + 1}
            </p>
            <button onClick={handleReveal} style={{ padding: '10px 20px', fontSize: '16px' }}>
              Reveal Question
            </button>
          </>
        ) : (
          <>
            <p style={{ fontWeight: 'bold' }}>Q: {currentQ.q}</p>
            <p>A: {currentQ.a}</p>
            <button
              onClick={handleCorrect}
              style={{ padding: '8px 16px', marginRight: '10px', cursor: 'pointer' }}
            >
              Mark Correct
            </button>
            <button onClick={handleNext} style={{ padding: '8px 16px', cursor: 'pointer' }}>
              Skip / Wrong
            </button>
          </>
        )}
      </div>
    </div>
  );
}

export default App;
